catalog_script_client.script:
function onSubmit() {
    var reqCategory = g_form.getValue('req_category');
    var msg = "";
    if (reqCategory == 'rfx_request') {
        if (window == null) {
            if (this.document.getElementsByClassName('get-attachment').length == 0) {
                msg = "";
                msg = "NOTE: Please attach either an Excel or Word document with the list of company names. Optional, but not required, information may include web address, phone number, or customer service email address.";
                g_form.addErrorMessage(msg);
                return false;
            }
        }
    } /*else if (reqCategory == 'change_request') {
        if (window == null) {
            if (this.document.getElementsByClassName('get-attachment').length == 0) {
                msg = "";
                msg = "NOTE: Please attach a completed 301-S form here.";
                g_form.addErrorMessage(msg);
                return false;
            }
        }
    } */else if (reqCategory == 'new_reactivate_request' && g_form.getValue('request_type')== "non_po_supplier" ) {
        if (window == null) {
            if (this.document.getElementsByClassName('get-attachment').length == 0) {
                msg = "";
                msg = "NOTE: For Non-PO Suppliers: You MUST attach a completed 301B form or the request will be rejected.";
                g_form.addErrorMessage(msg);
                return false;
            }
        }
    }
}
